// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  const statusFilter = req.query.status;
  try {
    const tasks = await tasksService.getTasks(projectId, statusFilter);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { title, description } = req.body;
  try {
    const task = await tasksService.createTask(projectId, title, description);
    res.status(201).json({ task });
  } catch (error) {
    if (error.code === 'INVALID_INPUT') {
      sendError(res, 400, error.code, error.message);
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

router.patch('/:taskId', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  try {
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    if (!updatedTask) {
      sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    } else {
      res.json({ task: updatedTask });
    }
  } catch (error) {
    if (error.code === 'INVALID_INPUT') {
      sendError(res, 400, error.code, error.message);
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const tasksStore = {};

const getTasks = async (projectId, statusFilter) => {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  let tasks = Object.values(tasksStore).filter(task => task.projectId === projectId);
  if (statusFilter) {
    tasks = tasks.filter(task => task.status === statusFilter);
  }
  return tasks;
};

const createTask = async (projectId, title, description) => {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  if (!title || !description) {
    throw { code: 'INVALID_INPUT', message: 'Title and description are required' };
  }
  const taskId = randomUUID();
  const task = {
    id: taskId,
    projectId,
    title,
    description,
    status: 'todo',
  };
  tasksStore[taskId] = task;
  return task;
};

const updateTaskStatus = async (projectId, taskId, status) => {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = tasksStore[taskId];
  if (!task || task.projectId !== projectId) {
    return null;
  }
  if (status !== 'todo' && status !== 'done') {
    throw { code: 'INVALID_INPUT', message: 'Invalid status' };
  }
  task.status = status;
  tasksStore[taskId] = task;
  return task;
};

module.exports = {
  getTasks,
  createTask,
  updateTaskStatus,
};

