  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  try {
    const member = await membersService.addMember(projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'INVALID_INPUT') {
      sendError(res, 400, error.code, error.message);
    } else if (error.code === 'DUPLICATE_USER') {
      sendError(res, 409, error.code, error.message);
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const membersStore = {};

const getMembers = async (projectId) => {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  return Object.values(membersStore).filter(member => member.projectId === projectId);
};

const addMember = async (projectId, userId, role) => {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  if (!userId || !role) {
    throw { code: 'INVALID_INPUT', message: 'User ID and role are required' };
  }
  const existingMember = membersStore[userId];
  if (existingMember && existingMember.projectId === projectId) {
    throw { code: 'DUPLICATE_USER', message: 'User already exists in this project' };
  }
  const member = {
    id: userId,
    projectId,
    role,
  };
  membersStore[userId] = member;
  return member;
};

module.exports = {
  getMembers,
  addMember,
};
const __botEvalMembersDupGuard = module.exports.addMember;
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const existing = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  if (Array.isArray(existing) && existing.some(member => member && String(member.userId || '') === userKey)) {
    return null;
  }
  if (typeof __botEvalMembersDupGuard === 'function') {
    return __botEvalMembersDupGuard(projectId, userId, role);
  }
  return null;
};

